arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR = 24
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0
$FOUND = $false

while ($ELAPSED -lt $TIMEOUT) {
    # Strategy A
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body | test("Copilot.s findings")) | {id: .id, body: (.body | .[0:200])}' 2>$null
    if ($reviews) { $FOUND = $true; Write-Host "Strategy A match"; break }

    # Strategy B
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.body | test("Pull request overview")) | {id: .id, body: (.body | .[0:200])}' 2>$null
    if ($reviews) { $FOUND = $true; Write-Host "Strategy B match"; break }

    # Strategy C
    $reviews = gh api "/repos/$REPO/pulls/$PR/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | {id: .id, user: .user.login, body: (.body | .[0:200])}' 2>$null
    if ($reviews) { $FOUND = $true; Write-Host "Strategy C match"; break }

    # Strategy D
    $comments = gh api "/repos/$REPO/pulls/$PR/comments" --jq '.[] | select(.user.login == "Copilot") | {id: .id, body: (.body | .[0:100])}' 2>$null
    if ($comments) { $FOUND = $true; Write-Host "Strategy D match"; break }

    Write-Host "No review yet (elapsed: ${ELAPSED}s). Waiting ${INTERVAL}s..."
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if ($FOUND) {
    Write-Host "=== REVIEW FOUND ==="
    Write-Host $reviews
    Write-Host $comments
} else {
    Write-Host "TIMEOUT: No Copilot review found after ${TIMEOUT}s"
}

